package org.apache.commons.csv;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.StringWriter;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testFormatWithNormalValues() throws IOException {
        String result = csvFormat.format("a", "b", "c");
        assertNotNull(result);
        String expected = "a,b,c";
        assertEquals(expected, result);
    }

    @Test
    public void testFormatWithEmptyValues() {
        String result = csvFormat.format();
        // Empty record results in empty string
        assertEquals("", result);
    }

    @Test
    public void testFormatWithNullValues() {
        String result = csvFormat.format((Object) null, "b", null);
        // nulls will print as empty (default), so commas between values remain
        assertEquals(",b,", result);
    }

    @Test
    public void testFormatIOExceptionIsWrapped() throws Exception {
        // Use reflection to mock CSVPrinter constructor to throw IOException on printRecord
        CSVFormat format = CSVFormat.DEFAULT;

        // Create a spy of CSVPrinter to throw IOException on printRecord
        CSVPrinter spyPrinter = spy(new CSVPrinter(new StringWriter(), format));
        doThrow(new IOException("io exception")).when(spyPrinter).printRecord(any());

        // Use reflection to replace CSVPrinter constructor call inside format method
        // Since we cannot mock constructor directly without Mockito 4+, we simulate by subclassing CSVFormat
        CSVFormat formatWithMock = new CSVFormat(format.getDelimiter(), format.getQuoteCharacter(), format.getQuoteMode(),
                format.getCommentMarker(), format.getEscapeCharacter(), format.getIgnoreSurroundingSpaces(),
                format.getIgnoreEmptyLines(), format.getRecordSeparator(), format.getNullString(),
                null, format.getHeader(), format.getSkipHeaderRecord(), format.getAllowMissingColumnNames(),
                format.getIgnoreHeaderCase(), format.getTrim(), format.getTrailingDelimiter(), format.getAutoFlush()) {
            @Override
            public String format(final Object... values) {
                final StringWriter out = new StringWriter();
                try (CSVPrinter printer = spyPrinter) {
                    printer.printRecord(values);
                    return out.toString().trim();
                } catch (final IOException e) {
                    throw new IllegalStateException(e);
                }
            }
        };

        IllegalStateException exception = assertThrows(IllegalStateException.class,
                () -> formatWithMock.format("a", "b"));
        assertTrue(exception.getMessage().isEmpty());
        assertTrue(exception.getCause() instanceof IOException);
        assertEquals("io exception", exception.getCause().getMessage());
    }
}
